package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    CSVParser parser;

    @BeforeEach
    void setUp() throws Exception {
        parser = Mockito.spy(new CSVParser(null, null));
        // Use reflection to replace the private nextRecord method behavior
        Field nextRecordField = CSVParser.class.getDeclaredField("nextRecord");
        nextRecordField.setAccessible(true);
        // Instead of overriding nextRecord (final class), use spy and doAnswer for nextRecord
        // But nextRecord is package-private, so we mock via spy and doAnswer on nextRecord method via Mockito
        // However, nextRecord is not public, so we mock with doAnswer on parser.nextRecord() via Mockito

        // Setup a counter in this test class to simulate nextRecord calls
        final int[] count = {0};
        final int max = 3;

        doAnswer(invocation -> {
            if (count[0] < max) {
                count[0]++;
                return mock(CSVRecord.class);
            }
            return null;
        }).when(parser).nextRecord();
    }

    @Test
    void testGetRecords_withEmptyCollection() throws IOException {
        List<CSVRecord> records = new ArrayList<>();
        List<CSVRecord> result = parser.getRecords(records);
        assertSame(records, result);
        assertEquals(3, records.size());
    }

    @Test
    void testGetRecords_withNonEmptyCollection() throws IOException {
        List<CSVRecord> records = new ArrayList<>();
        records.add(mock(CSVRecord.class));
        List<CSVRecord> result = parser.getRecords(records);
        assertSame(records, result);
        assertEquals(4, records.size());
    }

    @Test
    void testGetRecords_handlesIOException() throws IOException {
        CSVParser throwingParser = Mockito.spy(new CSVParser(null, null));
        doThrow(new IOException("forced")).when(throwingParser).nextRecord();
        List<CSVRecord> records = new ArrayList<>();
        IOException thrown = assertThrows(IOException.class, () -> {
            throwingParser.getRecords(records);
        });
        assertEquals("forced", thrown.getMessage());
    }
}
